import{_ as e,o as a,c as r,ag as i}from"./chunks/framework.CxZWPeXl.js";const p=JSON.parse('{"title":"History Tracking","description":"","frontmatter":{},"headers":[],"relativePath":"en/history.md","filePath":"en/history.md"}'),o={name:"en/history.md"};function n(s,t,d,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="history-tracking" tabindex="-1">History Tracking <a class="header-anchor" href="#history-tracking" aria-label="Permalink to &quot;History Tracking&quot;">​</a></h1><blockquote><p>Review all practice sessions, identify areas for improvement through filtering and analysis.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The History page provides a complete list of all your practice records, supporting multi-dimensional filtering and sorting, making it easy to find specific records to review or retry.</p><h2 id="accessing-the-page" tabindex="-1">Accessing the Page <a class="header-anchor" href="#accessing-the-page" aria-label="Permalink to &quot;Accessing the Page&quot;">​</a></h2><ul><li>The <strong>&quot;All&quot;</strong> option in the Dashboard&#39;s quick filter</li><li>Direct access to path <code>/practice-history</code></li></ul><h2 id="page-layout" tabindex="-1">Page Layout <a class="header-anchor" href="#page-layout" aria-label="Permalink to &quot;Page Layout&quot;">​</a></h2><p>The History page consists of the following areas:</p><ul><li><strong>Title Bar</strong>: Includes Title &quot;Practice Records&quot;, Filters button, Start Chat button</li><li><strong>Filter Tags</strong>: Displays the currently applied filter conditions</li><li><strong>History Table</strong>: Shows the complete history</li></ul><hr><h2 id="filtering-features" tabindex="-1">Filtering Features <a class="header-anchor" href="#filtering-features" aria-label="Permalink to &quot;Filtering Features&quot;">​</a></h2><p>Click the <strong>&quot;Filters&quot;</strong> button to open the filter panel. You can apply multiple filters simultaneously.</p><table tabindex="0"><thead><tr><th>Filter</th><th>Type</th><th>Options</th></tr></thead><tbody><tr><td>Age</td><td>Number Range</td><td>Min Age ~ Max Age (18-65)</td></tr><tr><td>Gender</td><td>Single Choice</td><td>Male / Female</td></tr><tr><td>Name</td><td>Text Input</td><td>By customer name</td></tr><tr><td>Income</td><td>Single Choice</td><td>5M~10M / 10M~15M / 15M~20M / &gt; 20M</td></tr><tr><td>Marital Status</td><td>Single Choice</td><td>Single / Married</td></tr><tr><td>Relationship</td><td>Single Choice</td><td>Family-Friends / Stranger</td></tr><tr><td>Stages Reached</td><td>Number Range</td><td>Min Stage ~ Max Stage</td></tr></tbody></table><hr><h2 id="history-table" tabindex="-1">History Table <a class="header-anchor" href="#history-table" aria-label="Permalink to &quot;History Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Date</td><td>Date and Time of the practice</td></tr><tr><td>Age</td><td>Age of the persona</td></tr><tr><td>Gender</td><td>Gender of the persona</td></tr><tr><td>Name</td><td>Name of the persona</td></tr><tr><td>Occupation</td><td>Occupation of the persona</td></tr><tr><td>Income</td><td>Income level</td></tr><tr><td>Marital Status</td><td>Single / Married</td></tr><tr><td>Children</td><td>Number of children</td></tr><tr><td>Relationship</td><td>Family-friends / Stranger</td></tr><tr><td>Stage Reached</td><td>The final sales stage reached</td></tr><tr><td>Duration</td><td>Duration of the session</td></tr><tr><td>Actions</td><td>Action options</td></tr></tbody></table><h3 id="action-buttons" tabindex="-1">Action Buttons <a class="header-anchor" href="#action-buttons" aria-label="Permalink to &quot;Action Buttons&quot;">​</a></h3><ul><li><strong>View Review</strong>: Navigate to the evaluation report to view detailed results.</li><li><strong>Retry</strong>: Start a completely new session using the exact same persona.</li><li><strong>Continue</strong>: Resume an unfinished session.</li></ul><hr><h2 id="practice-tips" tabindex="-1">Practice Tips <a class="header-anchor" href="#practice-tips" aria-label="Permalink to &quot;Practice Tips&quot;">​</a></h2><h3 id="identify-weaknesses" tabindex="-1">Identify Weaknesses <a class="header-anchor" href="#identify-weaknesses" aria-label="Permalink to &quot;Identify Weaknesses&quot;">​</a></h3><p>Filter by &quot;Stage Reached&quot; to find sessions that only reached Stage 1 or 2. Review the Evaluation Report to identify common weaknesses and target them in future practices.</p><h3 id="targeted-practice" tabindex="-1">Targeted Practice <a class="header-anchor" href="#targeted-practice" aria-label="Permalink to &quot;Targeted Practice&quot;">​</a></h3><p>Use filters (like Income, Marital Status) to find specific types of personas. Then, use the &quot;Retry&quot; feature to familiarize yourself with challenging scenarios.</p><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li>Return to the <a href="./dashboard.html">Dashboard</a></li><li>Understand the <a href="./evaluation.html">Evaluation &amp; Feedback</a></li><li>Start a new <a href="./practice.html">Practice Simulation</a></li></ul>',27)])])}const g=e(o,[["render",n]]);export{p as __pageData,g as default};
